var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"제가 처음으로 본 사장님은, 보기 드물게 많은 위협에 노출되어 계신 분이셨습니다.","JPN":"私が初めて見た時の社長は、最近にしては珍しく様々な危険にさらされている方でした。","ENG":"When I first met you, you were exposed to many threats, maybe more than anyone else I've ever met in my life.","TWN":"我第一次見到老闆時，老闆正面對著前所未有的威脅。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"경호 중에 발견한 폭발물과 독극물을 망라하면, 지금까지 무사하신 게 놀라울 지경입니다.","JPN":"警護中に発見した爆発物や毒物を並べると、今まで無事だったことに驚くばかりです。","ENG":"Considering the amount of explosives and poison I've discovered so far while scanning, it's almost a miracle that you're still alive.","TWN":"如果把護衛中發現的爆裂物和毒藥都算進去，您能活到現在簡直就是奇蹟。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"그럼에도 주위의 시선과 관계없이 자신의 의지를 관철하기 위해 분투하시는 모습에...... 가슴이 설레었습니다.","JPN":"それにもかかわらず、人の目を気にせず、自分の意志を貫くために必死に努力する姿に……ときめきを覚えました。","ENG":"But you weathered the oppositions, determined to fulfill the vows you made with yourself. I was... moved.","TWN":"但就算如此，對於您無視周圍的眼光，為了貫徹自己的理想而奮鬥的身姿……我不禁怦然心跳。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"무사로서 사사로운 마음은 버리고자 했지만......","JPN":"警護役として私情を慎むべきですが……","ENG":"As a warrior, I worked my whole life trying not to let my emotions take over me.","TWN":"作為武士，我理應捨棄了私心……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"정신을 차리니 언제부턴가...... 사장님을 걱정하는 것을 억누르기 어려워지더군요.","JPN":"気づいたらいつの間にか……社長が心配で居ても立っても居られなくなりました。","ENG":"But before I knew it, I was fearing for your safety.","TWN":"但察覺到的時候，不知道從什麼時候開始……我已經無法不去擔心老闆了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"제가 검을 배우기 시작한 이유는 가문을 위해서나 경지에 다다르기 위해서도 아닙니다.","JPN":"私が剣を習い始めたきっかけは、家門のためだとか境地に達するためでもありません。","ENG":"My decision to walk the path of a swordsman was not for my family nor my personal ambitions. ","TWN":"我會開始學習劍術，不是為了家門，也不是為了達到某種境界。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"그저...... 지켜야 할 사람도 지키지 못하는 한심한 저 자신을 보기 싫어서였어요.","JPN":"ただ……守るべき人すら守れない、情けない自分が嫌だったからです。","ENG":"I just... I just hated myself for being so weak, unable to protect the people that should have been protected.","TWN":"只是……討厭那個無法守護必須守護的人，那個丟臉自己。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"......네. 당주님의, 언니의 안전을 위해서였죠.","JPN":"……はい。当主の……姉上の安全を守るためでした。","ENG":"Yes, everything was for Lady Nanahara, my sister.","TWN":"……沒錯。是為了家主，為了姐姐的安全。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"비명을 듣는 것도, 피가 튀는 것도 진저리가 났지만 참아 왔습니다. 그렇게 제 나약한 마음을 단련해 왔다고 생각했어요.","JPN":"悲鳴を聞くことも、血が飛び散ることもうんざりでしたが、耐えてきました。そうやって弱い心を鍛えてきたと思いました。","ENG":"Screams made my heart drop. I was disgusted by the blood splattered on my face. And living like that, I thought I was hardening my weak mind.","TWN":"耳邊的慘叫也好，飛濺的鮮血也好，都令我心驚膽戰，但我一路忍了過來。我想，我就是這樣鍛鍊自己軟弱的內心。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"하지만...... 이곳에서 지내면서 깨달았습니다. 당주님은 홀로 가문을 이끌 만큼 충분히 성장하셨어요.","JPN":"ですが……ここで過ごしてる間に気がつきました。当主は、一人で家門を率いるほど成長されたのだと。","ENG":"However... I realized during my time here. Lady Nanahara is capable enough to lead the family on her own. ","TWN":"但是……在這裡的生活讓我領悟到，家主已經得到了充分的成長，足以獨自帶領家族了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"저는 여전히...... 당주님을 지켜드리던 자신에게 안주하고 있었던 겁니다.","JPN":"私はいまだに……当主をお守りする自分の姿に満足していたのです。","ENG":"It was me that needed change. I was complacent about my role as a guard of Lady Nanahara.","TWN":"但我仍然……只想著守在家主身邊，安於現狀。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"그러니 이제부턴 저 역시 당주님처럼 한걸음 더 나아가고자 합니다.","JPN":"ですから、これからは私も当主のように一歩前進したいと思います。","ENG":"And now, I'd like to take a new step in my life, just as Lady Nanahara did.","TWN":"所以從現在，我也想像家主一樣，一步一步地前進。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"예를 갖춰 인사드립니다. 제가 진심으로 곁에서 모시길 바라는 분께.","JPN":"改めまして、ご挨拶申し上げます。私が真心を込めて仕えたい方に。","ENG":"So I would like to plead allegiance to the person I truly want to serve.","TWN":"盡我最大的禮儀，向我由衷希望侍於身邊的人致意。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};